:root {
  --btn-bg: #0066cc;
  --btn-text: #ffffff;
  --btn-hover: #0052a3;
  --btn-disabled-bg: #ccc;
  --btn-disabled-text: #666;
}
.btn {
  background: var(--btn-bg);
  color: var(--btn-text);
  padding: 0.75rem 1.5rem;
  border: none;
  border-radius: 6px;
  cursor: pointer;
}
.btn:hover {
  background: var(--btn-hover);
}
.btn:focus-visible {
  outline: 3px solid var(--btn-bg);
  outline-offset: 2px;
}
.btn:disabled {
  background: var(--btn-disabled-bg);
  color: var(--btn-disabled-text);
  cursor: not-allowed;
}

